Your task is to write a Jest test case that exposes a specific mutation in a JavaScript/TypeScript project.

MUTATION DETAILS
The mutation affects the following file:
index.js
Here is the full content of that file (shown with a <PLACEHOLDER> marker):
'use strict';

var rules = []

function type(obj) {
  return Object.prototype.toString.call(obj).slice(8, -1)
}

function addRule(match, result) {
  rules.unshift([match, result])
  return plural
}

// words like cherry, where a word ends in a y, but the letter before the y is a consonant
// also contains unique rule for words that end with 'quy' (soliloquy)
   <PLACEHOLDER>


// words that end with ch, x, s append 'es'
addRule(/x$|ch$|s$/i, function(w) { return w + 'es' })

// words that maintain latin/greek plural
addRule(/nucleus|syllabus|focus|fungus|cactus/i, function(w) { return w.substr(0, w.length - 2) + 'i' });
addRule(/thesis|crisis/i, function(w) { return w.substr(0, w.length - 2) + 'es' });
addRule(/appendix|index/i, function(w) { return w.substr(0, w.length - 2) + 'ices' });

// stereo -> stereos
addRule(/[aeiouy]o$/i, function(w) { return w + 's' });
addRule(/[^aeiouy]o$/i, function(w) { return w + 'es' });

// f/fe ending words gets switched to ves
// unless it's dwarf or roof
addRule(/(fe?$)/i, function(w, regex) {
  if (w === 'dwarf' || w === 'roof') {
    return w + 's'
  }
  return w.replace(regex, 'ves')
})

addRule('criterion', 'criteria')
addRule('bacterium', 'bacteria')
addRule('memo', 'memos')
addRule('cello', 'cellos')
addRule('die', 'dice')
addRule('goose', 'geese')
addRule('mouse', 'mice')
addRule('person', 'people')
addRule('chilli', 'chillies')

addRule(/^(?:wo)?man$/i, function(w) { return w.replace(/a/, 'e') })

// animals w/ no plural
addRule(/\b(?:bison|cod|deer|fowl|halibut|moose|sheep)\b/i, function(w) { return w })

// singular nouns that end in -s
var tools = ['goggle', 'scissor', 'plier', 'tong', 'tweezer']
var clothes = ['trouser', 'pant', 'pantie', 'clothe']
var games = ['billiard', 'bowl', 'card', 'dart', 'skittle', 'draught']
var illnesses = ['diabete', 'measle', 'mump', 'rabie', 'ricket', 'shingle']
var misc = ['kudo', 'premise', 'shamble', 'glasse', 'spectacle', 'jitter',
  'alm', 'fece', 'bowel', 'sud', 'entrail', 'electronic', 'outskirt', 'odd', 'tropic',
  'riche', 'surrounding', 'thank', 'heroic', 'remain', 'amend'
]
addRule(new RegExp('\\b(?:' + tools.concat(clothes, games, illnesses, misc).join('|') + ')s\\b', 'i'), function(w) { return w})

// most words ending in -ics are the same in their plural form
// mathematics, statistics, linguistics, classics, acoustics
addRule(/ics$/i, function(w) { return w })

// uncountable
addRule(/\b(?:tea|sugar|water|air|rice|knowledge|beauty|anger|fear|love|money|research|safety|evidence)\b/i, function(w) { return w })

function plural(word, num) {
  var i
    , rule

  if (num !== 1 || num === undefined) {
    for (i = 0; i < rules.length; i++) {
      rule = rules[i]

      if (type(rule[0]) === 'RegExp' && rule[0].test(word)) {
        return type(rule[1]) === 'Function' ? rule[1](word, rule[0]) : rule[1]
      }
      if (type(rule[0]) === 'String' && rule[0] === word) {
        return type(rule[1]) === 'Function' ? rule[1](word) : rule[1]
      }

    }

    return word + 's'
  }
  return word
}

module.exports = plural

module.exports.addRule = addRule

module.exports.unmonkeyPatch = function() {
  String.prototype.plural = null;
}

module.exports.monkeyPatch = function() {
  if (String.prototype.plural === undefined) {
    String.prototype.plural = function(num) {
      return plural(this, num)
    }
  }
  else {
    throw new Error('Unable to add plural function to String object')
  }
}

module.exports.VERSION = require('./package.json').version

In the original code, <PLACEHOLDER> has the value:

-   addRule(/[^aeiou]y$|quy$/i, function(w) { return w.substr(0, w.length - 1) + 'ies' })
In the mutated code, <PLACEHOLDER> has the value:

+   addRule(/[^aeiou]y$|quy/i, function(w) { return w.substr(0, w.length - 1) + 'ies' })


YOUR TASK
Write one Jest test file that:
    1. Passes when run against the original code.
    2. Fails when run against the mutated code.
    3. Tests the behavior of the mutated file in a way that reliably detects the mutation.
The test will be saved at the following path, relative to this test-generation project’s root:
llm-cache/anthropic_claude-sonnet-4.6/temp_0.5/withoutTests/cached/artifacts/plural/attempt_1/pending_category/mutant-8990ea6/testCase.test.ts

ALLOWED LIBRARIES
You may use:
    1. Any built-in Node.js modules (e.g., fs, path, crypto, etc.).

You may not use any other third-party libraries.

The mutation changes `/[^aeiou]y$|quy$/i` to `/[^aeiou]y$|quy/i` - removing the `$` anchor from the `quy` alternative. This means the mutated regex will match any word containing "quy" anywhere, not just at the end.

To detect this, I need a word that:
1. Contains "quy" but NOT at the end
2. Should NOT be pluralized with the "ies" suffix in the original
3. WILL be incorrectly matched by the mutated regex

A word like "quay" contains "qua" not "quy". Let me think of a word with "quy" not at the end... "quyen" or something similar. Actually, let me think differently.

The key difference: in the original, `quy$` only matches words ending in "quy". In the mutant, `quy` matches words containing "quy" anywhere.

A word like "quys" - wait, that's not a real word but let's think about what would happen. A word ending in "quys" would contain "quy" but not at the end (it ends in "quys"). The original wouldn't match it with the quy rule, but the mutant would.

Actually, let me think about "soliloquy" - it ends in "quy" so both should match it. 

What about a word like "quys" - contains "quy" but ends in "s". The original wouldn't match (no `$` match for "quy" at end), the mutant would match "quy" in the middle.

Let me use a test word that ends in "quys" - the plural form. Actually, let me use "quys" directly - original returns "quys" + "s" = "quyss"? No...

Better: use a word ending in "quys" - the mutant would incorrectly apply the "ies" rule. For example, "buys" contains "uys" not "quy". 

Let me use "quys" - original: no match for `[^aeiou]y$` (ends in 's'), no match for `quy$` (ends in 's'), so returns "quys" + "s" = "quyss". Mutant: matches `quy` (contains "quy"), returns "quys".substr(0, 3) + "ies" = "quies". 

Wait, original returns "quyss" and mutant returns "quies" - both are wrong but they differ, which is what we need.

```typescript
import plural from "../../../../../../../../../../../subject_repositories/plural/index.js"

describe('plural - quy rule mutation detection', () => {
  it('should not apply the -ies suffix to a word containing "quy" but not ending in "quy"', () => {
    // The word "quys" contains "quy" but does not end with "quy"
    // Original regex: /[^aeiou]y$|quy$/i - requires "quy" at the END of the word
    // Mutated regex: /[^aeiou]y$|quy/i - matches "quy" ANYWHERE in the word
    // Original: "quys" doesn't match either pattern, returns "quyss"
    // Mutant: "quys" matches "quy" (not anchored), applies ies rule -> "quies"
    const result = plural('quys')
    // Original code: no rule matches "quys", so it appends 's' -> "quyss"
    expect(result).toBe('quyss')
  })
})
```

Looking at the mutation more carefully:

- Original: `/[^aeiou]y$|quy$/i` - matches words ending in consonant+y OR ending in "quy"
- Mutated: `/[^aeiou]y$|quy/i` - matches words ending in consonant+y OR containing "quy" anywhere

I need a word that:
1. Contains "quy" but NOT at the end
2. Would NOT match `[^aeiou]y$` either
3. The original would NOT apply the ies rule, but the mutant WOULD

"quys" ends in "s" so it matches the `/x$|ch$|s$/i` rule and gets "es" appended → "quyses". That's why the original gives "quyses".

For the mutant, "quys" would match `quy` (not anchored), so it would return `"quys".substr(0, 3) + "ies"` = `"quies"`.

So the test should expect "quyses" (original) and the mutant would return "quies".

```typescript
import plural from "../../../../../../../../../../../subject_repositories/plural/index.js"

describe('plural - quy rule mutation detection', () => {
  it('should apply the -es suffix to "quys" (ends in s) rather than the -ies suffix', () => {
    // "quys" ends in 's', so the /x$|ch$|s$/i rule applies -> "quyses"
    // Original regex: /[^aeiou]y$|quy$/i - "quys" does NOT end in "quy", so quy rule doesn't match
    // Mutated regex: /[^aeiou]y$|quy/i - "quys" CONTAINS "quy", so mutant incorrectly applies ies rule -> "quies"
    const result = plural('quys')
    expect(result).toBe('quyses')
  })
})
```
